var argv = require('optimist')
    .describe('group', 'Group to address')
    .default('group', 1)
    .alias('g', 'group')
    .describe('channel', 'Channel to address')
    .default('channel', 1)
    .alias('c', 'channel')
    .describe('output', 'Set outputs. (0) sink (1) do not.')
    .alias('o', 'output')
    .describe('device', 'Select device type.')
    .default('device', 'usb:CLASS_AN2053')
    .alias('d', 'device')
    .argv;

var vita = require('..');
var an2053 = vita.open(argv.device);

//var stuff = function() {
//argv.output = -1 * argv.output;
if ("output" in argv) {
	console.log("setOutputs");
		an2053.setOutputs(argv.group, argv.channel, argv.output, function(err) {
		if (err) {
			console.log("\tError: " + err);
		} else {
			console.log('\tOutputs set to 0x%s', argv.output.toString(16));
			console.log(argv.output.toString(10));
		}
	});
}
